import { useState, useEffect, useRef } from "react";

// ── 반응형 뷰포트 훅 ──
function useViewport(){
  const [vw,setVw]=useState(window.innerWidth);
  const [vh,setVh]=useState(window.innerHeight);
  useEffect(()=>{
    const fn=()=>{setVw(window.innerWidth);setVh(window.innerHeight);};
    window.addEventListener("resize",fn);
    window.addEventListener("orientationchange",fn);
    return()=>{window.removeEventListener("resize",fn);window.removeEventListener("orientationchange",fn);};
  },[]);
  // 폴더블 내부 화면: 보통 320~380px
  // 일반 스마트폰: 360~430px
  // 폴더블 펼쳤을 때: 500~800px
  const isNarrow=vw<360;      // 폴더블 접힌 상태
  const isWide=vw>=500;       // 폴더블 펼친 상태 or 태블릿
  const isMid=!isNarrow&&!isWide; // 일반 스마트폰
  const scale=isNarrow?0.82:isWide?1.15:1;
  return{vw,vh,isNarrow,isWide,isMid,scale};
}

