// 원 단위 포맷
const fmtWon=n=>Math.round(n).toLocaleString("ko-KR")+"원";
const fmtWonOnly=n=>Math.round(n).toLocaleString("ko-KR");

// ── 대출 계산기 ──────────────────────────────────────────────
function LoanCalc(){
  const [vals,setVals]=useState({lp:"2900000000",ltv:50,rt:"3.8",yr:"30"});
  const [result,setResult]=useState(null);
  const set=(k,v)=>setVals(p=>({...p,[k]:v}));

  const calc=()=>{
    const lp=+vals.lp||0,ltv=vals.ltv,rt=+vals.rt||0,yr=+vals.yr||0;
    const la=Math.floor(lp*ltv/100); // 원 단위
    const mr=rt/100/12,n=yr*12;
    const mp=la>0&&mr>0?la*mr*Math.pow(1+mr,n)/(Math.pow(1+mr,n)-1):0;
    const totalInt=mp*n-la;
    setResult({la,n,mp,totalInt});
  };

  const lp=+vals.lp||0,ltv=vals.ltv;
  const la=Math.floor(lp*ltv/100);

  return(
    <>
      <CalcCard title="대출 원리금 계산기" icon="🏦">
        <CInput label="매매가" value={vals.lp} onChange={e=>set("lp",e.target.value)} unit="원"/>
        <div style={{marginBottom:14}}>
          <CLabel t={`LTV ${ltv}% — 대출금 약 ${la.toLocaleString()}원`}/>
          <input type="range" min={10} max={80} value={ltv} onChange={e=>set("ltv",+e.target.value)}
            style={{width:"100%",accentColor:C.gold,height:4,cursor:"pointer"}}/>
          <div style={{display:"flex",justifyContent:"space-between",marginTop:4}}>
            <span style={{fontSize:10,color:C.textMuted}}>10%</span>
            <span style={{fontSize:10,color:C.textMuted}}>80%</span>
          </div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <CInput label="금리" value={vals.rt} onChange={e=>set("rt",e.target.value)} step="0.1" unit="%"/>
          <CInput label="상환기간" value={vals.yr} onChange={e=>set("yr",e.target.value)} unit="년"/>
        </div>
        <CBtn onClick={calc}>대출 계산하기</CBtn>
        {result&&(
          <ResultBox>
            <ResultRow k="대출금액" v={fmtWon(result.la)}/>
            <ResultRow k="월 납입금" v={fmtWon(result.mp)} highlight/>
            <ResultRow k="총 납입이자" v={fmtWon(result.totalInt)}/>
            <ResultRow k="총 납입액" v={fmtWon(result.mp*result.n)}/>
          </ResultBox>
        )}
      </CalcCard>
    </>
  );
}

// ── 월세전환 계산기 ──────────────────────────────────────────
function RentConvertCalc(){
  const [vals,setVals]=useState({deposit:"900000000",monthly:"2000000",rate:"5"});
  const [result,setResult]=useState(null);
  const set=(k,v)=>setVals(p=>({...p,[k]:v}));

  const calc=()=>{
    const d=+vals.deposit||0,m=+vals.monthly||0,r=+vals.rate||5;
    const toJeonse=Math.round(d+m*12/r*100);
    setResult({toJeonse,monthly:m});
  };

  return(
    <CalcCard title="월세 ↔ 전세 환산" icon="🔄">
      <CInput label="보증금" value={vals.deposit} onChange={e=>set("deposit",e.target.value)} unit="원"/>
      <CInput label="월세" value={vals.monthly} onChange={e=>set("monthly",e.target.value)} unit="원"/>
      <CInput label="전월세 전환율" value={vals.rate} onChange={e=>set("rate",e.target.value)} step="0.1" unit="%"/>
      <CBtn onClick={calc}>환산 계산하기</CBtn>
      {result&&(
        <ResultBox>
          <ResultRow k="동등 전세가" v={fmtWon(result.toJeonse)} highlight/>
          <ResultRow k="연간 임대료 상당액" v={fmtWon(result.monthly*12)}/>
        </ResultBox>
      )}
    </CalcCard>
  );
}

// ── 취득세 계산기 ──────────────────────────────────────────
function AcqTaxCalc(){
  const [vals,setVals]=useState({price:"2900000000",houses:"1"});
  const [result,setResult]=useState(null);
  const set=(k,v)=>setVals(p=>({...p,[k]:v}));

  const calc=()=>{
    const price=+vals.price||0,hc=+vals.houses;
    // 원 단위 기준 구간 (6억=600000000, 9억=900000000)
    const rate=hc===1?(price<600000000?1:price<900000000?2:3):hc===2?8:12;
    const acq=Math.round(price*rate/100);
    const rural=Math.round(acq*0.1);
    const edu=Math.round(acq*0.2);
    setResult({rate,acq,rural,edu,total:acq+rural+edu});
  };

  return(
    <CalcCard title="취득세 계산기" icon="📋">
      <CInput label="취득가액" value={vals.price} onChange={e=>set("price",e.target.value)} unit="원"/>
      <CLabel t="보유 주택 수"/>
      <CToggle
        options={[["1","1주택"],["2","2주택"],["3","3주택+"]]}
        value={vals.houses}
        onChange={v=>set("houses",v)}
      />
      <CBtn onClick={calc}>취득세 계산하기</CBtn>
      {result&&(
        <ResultBox>
          <ResultRow k="취득세율" v={`${result.rate}%`}/>
          <ResultRow k="취득세" v={fmtWon(result.acq)}/>
          <ResultRow k="농어촌특별세" v={fmtWon(result.rural)} sub/>
          <ResultRow k="지방교육세" v={fmtWon(result.edu)} sub/>
          <div style={{paddingTop:10,marginTop:6,borderTop:"1px solid rgba(201,168,76,0.25)",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{color:C.gold,fontSize:13,fontWeight:600}}>총 납부세액</span>
            <span style={{color:C.goldLight,fontWeight:800,fontSize:20}}>{fmtWon(result.total)}</span>
          </div>
        </ResultBox>
      )}
    </CalcCard>
  );
}

// ── 보유세 계산기 ──────────────────────────────────────────
function HoldTaxCalc(){
  const [vals,setVals]=useState({h1:"3400000000",h2:"0",h3:"0",ownership:"single",age:"0",hold:"0"});
  const [result,setResult]=useState(null);
  const set=(k,v)=>setVals(p=>({...p,[k]:v}));

  const calc=()=>{
    const houses=[+vals.h1,+vals.h2,+vals.h3].filter(v=>v>0);
    if(houses.length===0) return;
    const totalMkt=houses.reduce((a,b)=>a+b,0); // 이미 원 단위
    const pubPrices=houses.map(h=>h*0.68);
    const totalPub=pubPrices.reduce((a,b)=>a+b,0);
    let propTax=0;
    pubPrices.forEach(pub=>{
      const base=pub*0.60;
      if(base<=60000000) propTax+=base*0.001;
      else if(base<=150000000) propTax+=60000+(base-60000000)*0.0015;
      else if(base<=300000000) propTax+=195000+(base-150000000)*0.0025;
      else propTax+=570000+(base-300000000)*0.004;
    });
    const propTaxTotal=propTax*1.2+totalPub*0.60*0.0014;
    const isMulti=vals.ownership==="multi";
    const deduction=vals.ownership==="joint"?1800000000:isMulti?900000000:1200000000;
    const jongBase=Math.max(0,totalPub*0.60-deduction);
    let jongTax=0;
    if(isMulti){
      if(jongBase<=300000000) jongTax=jongBase*0.012;
      else if(jongBase<=600000000) jongTax=3600000+(jongBase-300000000)*0.016;
      else if(jongBase<=1200000000) jongTax=8400000+(jongBase-600000000)*0.022;
      else jongTax=21600000+(jongBase-1200000000)*0.036;
    } else {
      if(jongBase<=300000000) jongTax=jongBase*0.005;
      else if(jongBase<=600000000) jongTax=1500000+(jongBase-300000000)*0.007;
      else if(jongBase<=1200000000) jongTax=3600000+(jongBase-600000000)*0.01;
      else jongTax=9600000+(jongBase-1200000000)*0.014;
    }
    if(vals.ownership==="single"&&jongTax>0){
      jongTax=jongTax*(1-Math.min((+vals.age+ +vals.hold)/100,0.8));
    }
    const jongTotal=jongTax*1.2;
    setResult({totalMkt,totalPub,propTaxTotal,jongTotal,total:propTaxTotal+jongTotal});
  };

  return(
    <>
      <CalcCard title="보유세 시뮬레이터" icon="🏛️">
        <div style={{color:C.textMuted,fontSize:12,marginBottom:14,lineHeight:1.6,background:"rgba(201,168,76,0.06)",borderRadius:8,padding:"8px 12px",border:"1px solid rgba(201,168,76,0.15)"}}>💡 소유 주택 시세를 입력하세요. 없는 주택은 0으로 두세요.</div>
        <CInput label="1주택 시세" value={vals.h1} onChange={e=>set("h1",e.target.value)} unit="원"/>
        <CInput label="2주택 시세 (없으면 0)" value={vals.h2} onChange={e=>set("h2",e.target.value)} unit="원"/>
        <CInput label="3주택 시세 (없으면 0)" value={vals.h3} onChange={e=>set("h3",e.target.value)} unit="원"/>
      </CalcCard>

      <CalcCard title="명의 및 공제 설정" icon="⚙️">
        <CLabel t="명의 구분"/>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,marginBottom:14}}>
          {[["single","1주택 단독"],["joint","부부 공동"],["multi","다주택자"]].map(([v,l])=>(
            <button key={v} onClick={()=>set("ownership",v)}
              style={{padding:"10px 4px",borderRadius:10,border:`1.5px solid ${vals.ownership===v?C.gold:C.cardBorder}`,background:vals.ownership===v?"rgba(201,168,76,0.1)":"#F8F9FB",color:vals.ownership===v?C.gold:C.textSecondary,fontWeight:vals.ownership===v?700:400,fontSize:11,cursor:"pointer"}}>
              {l}
            </button>
          ))}
        </div>
        {vals.ownership==="single"&&<>
          <CSelect label="연령 공제" value={vals.age} onChange={e=>set("age",e.target.value)}
            options={[["0","해당없음 (0%)"],["10","60~64세 (10%)"],["20","65~69세 (20%)"],["30","70~74세 (30%)"],["40","75세+ (40%)"]]}/>
          <CSelect label="장기보유 공제" value={vals.hold} onChange={e=>set("hold",e.target.value)}
            options={[["0","해당없음 (0%)"],["20","5~10년 (20%)"],["40","10~15년 (40%)"],["50","15년+ (50%)"]]}/>
        </>}
        <CBtn onClick={calc}>보유세 계산하기</CBtn>
      </CalcCard>

      {result&&(
        <CalcCard title="예상 보유세 결과" icon="📊">
          <ResultBox>
            <ResultRow k="총 시세 합계" v={fmtWon(result.totalMkt)}/>
            <ResultRow k="총 공시가격 (현실화율 68%)" v={fmtWon(result.totalPub)}/>
            <ResultRow k="재산세 (도시지역분·교육세 포함)" v={fmtWon(result.propTaxTotal)}/>
            <ResultRow k="종합부동산세 (농특세 포함)" v={fmtWon(result.jongTotal)}/>
            <div style={{paddingTop:10,marginTop:6,borderTop:"1px solid rgba(201,168,76,0.25)",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{color:C.gold,fontSize:13,fontWeight:600}}>1년 총 예상 보유세</span>
              <span style={{color:C.goldLight,fontWeight:800,fontSize:20}}>{fmtWon(result.total)}</span>
            </div>
          </ResultBox>
          <CalcWarn/>
        </CalcCard>
      )}
    </>
  );
}

// ── 양도세 계산기 ──────────────────────────────────────────
function TransferTaxCalc(){
  const [vals,setVals]=useState({
    houseType:"1",acqDate:"2010",transferDate:"2025",
    liveYears:"2이상",
    appraisal:"200000000",divPrice:"300000000",
    orgAcq:"100000000",expenses:"5000000",
  }); // 모두 원 단위
  const [result,setResult]=useState(null);
  const set=(k,v)=>setVals(p=>({...p,[k]:v}));

  const RATIO=2.62;
  const appr=+vals.appraisal||0;
  const divP=+vals.divPrice||0;
  const rightVal=appr*RATIO;
  const refund=Math.max(0,rightVal-divP);
  const burden=Math.max(0,divP-rightVal);

  const calc=()=>{
    if(refund<=0) return;
    const orgAcq=+vals.orgAcq||0;
    const exp=+vals.expenses||0;
    const allocAcq=orgAcq*(refund/appr);
    const allocExp=exp*(refund/appr);
    const gain=refund-allocAcq-allocExp;
    const is1=vals.houseType==="1";
    const isNonTax=is1&&vals.liveYears!=="2미만"&&rightVal<=1200000000;
    const taxableGain=isNonTax?0:is1&&rightVal>1200000000?gain*(1-1200000000/rightVal):gain;
    const holdYrs=Math.max(0,(+vals.transferDate)-(+vals.acqDate));
    let ltcRate=0;
    if(is1&&vals.liveYears!=="2미만"){
      const ly={"2이상":2,"3이상":3,"4이상":4,"5이상":5,"6이상":6,"7이상":7,"8이상":8,"9이상":9,"10이상":10}[vals.liveYears]||2;
      ltcRate=Math.min(holdYrs*0.04+ly*0.04,0.8);
    } else {
      ltcRate=holdYrs>=15?0.3:holdYrs>=10?0.2:holdYrs>=5?0.1:0;
    }
    const ltcAmt=taxableGain>0?taxableGain*ltcRate:0;
    const taxBase=Math.max(0,taxableGain-ltcAmt-2500000);
    const brackets=[[14000000,0.06,0],[50000000,0.15,1260000],[88000000,0.24,5760000],[150000000,0.35,15440000],[300000000,0.38,19940000],[500000000,0.40,25940000],[Infinity,0.42,35940000]];
    const [,rate,prog]=brackets.find(([limit])=>taxBase<=limit)||brackets[brackets.length-1];
    const yangdo=Math.max(0,taxBase*rate-prog);
    const local=Math.round(yangdo*0.1);
    setResult({gain,taxableGain,ltcRate,ltcAmt,taxBase,rate,yangdo,local,total:yangdo+local,isNonTax,allocAcq,allocExp,refund});
  };

  return(
    <>
      <CalcCard title="환급금 양도세 계산기" icon="💰">
        <div style={{color:C.textMuted,fontSize:12,marginBottom:14,lineHeight:1.6,background:"rgba(201,168,76,0.06)",borderRadius:8,padding:"8px 12px",border:"1px solid rgba(201,168,76,0.15)"}}>💡 재건축 환급금(청산금) 수령에 따른 양도소득세를 계산합니다</div>
        <CLabel t="주택 수 (환급일 기준)"/>
        <CToggle options={[["1","1주택"],["2","2주택 (1+1)"]]} value={vals.houseType} onChange={v=>set("houseType",v)}/>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <CInput label="취득 연도" value={vals.acqDate} onChange={e=>set("acqDate",e.target.value)} placeholder="2010"/>
          <CInput label="환급금 지급 연도" value={vals.transferDate} onChange={e=>set("transferDate",e.target.value)} placeholder="2025"/>
        </div>
        {vals.houseType==="1"&&(
          <CSelect label="거주 기간" value={vals.liveYears} onChange={e=>set("liveYears",e.target.value)}
            options={[["2미만","2년 미만 (비과세 미충족)"],["2이상","2년 이상 (비과세 충족)"],["3이상","3년 이상"],["4이상","4년 이상"],["5이상","5년 이상"],["6이상","6년 이상"],["7이상","7년 이상"],["8이상","8년 이상"],["9이상","9년 이상"],["10이상","10년 이상"]]}/>
        )}
      </CalcCard>

      <CalcCard title="평가 금액 입력" icon="📐">
        <CInput label="감정가격 — 종전평가액" value={vals.appraisal} unit="원" onChange={e=>set("appraisal",e.target.value)}/>
        <CInput label="조합원 분양가 — 옵션 포함" value={vals.divPrice} unit="원" onChange={e=>set("divPrice",e.target.value)}/>

        {/* 권리가액 / 환급금 미리보기 */}
        <div style={{background:"rgba(13,27,42,0.04)",borderRadius:10,padding:"12px 14px",marginBottom:14,border:`1px solid ${C.cardBorder}`}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
            <span style={{color:C.textMuted,fontSize:12}}>권리가액 (비례율 262%)</span>
            <span style={{color:C.navy,fontWeight:700,fontSize:13}}>{(rightVal/100000000).toFixed(2)}억원</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{color:refund>0?"#E74C3C":"#27AE60",fontSize:12,fontWeight:700}}>{refund>0?"💰 환급금":"💸 분담금"}</span>
            <span style={{color:refund>0?"#E74C3C":"#27AE60",fontWeight:800,fontSize:16}}>{((refund||burden)/100000000).toFixed(2)}억원</span>
          </div>
        </div>

        <CInput label="종전주택 취득가액" value={vals.orgAcq} unit="원" onChange={e=>set("orgAcq",e.target.value)}/>
        <CInput label="필요경비 — 취득세·중개보수 등" value={vals.expenses} unit="원" onChange={e=>set("expenses",e.target.value)}/>
        <CBtn onClick={calc} disabled={refund<=0}>
          {refund>0?"환급금 양도세 계산하기":"환급금 없음 (분담금 납부 대상)"}
        </CBtn>
      </CalcCard>

      {result&&(
        <CalcCard title="양도세 계산 결과" icon="📊">
          <ResultBox>
            {result.isNonTax?(
              <div style={{textAlign:"center",padding:"14px 0"}}>
                <div style={{fontSize:28,marginBottom:8}}>✅</div>
                <div style={{color:"#52D68A",fontSize:17,fontWeight:800,marginBottom:6}}>비과세 대상</div>
                <div style={{color:"rgba(255,255,255,0.4)",fontSize:12}}>1세대 1주택 비과세 요건 충족</div>
              </div>
            ):(
              <>
                {[
                  ["환급금 양도가액",fmtWon(result.refund),false],
                  [`안분 취득가액 (-)`,"-"+fmtWon(result.allocAcq),false],
                  [`안분 필요경비 (-)`,"-"+fmtWon(result.allocExp),false],
                  ["환급금 양도차익",fmtWon(result.gain),false],
                  [`장특공제 ${Math.round(result.ltcRate*100)}% (-)`,"-"+fmtWon(result.ltcAmt),false],
                  ["기본공제 (-)","-250만원",false],
                  ["과세표준",fmtWon(result.taxBase),false],
                  ["적용 세율",`${Math.round(result.rate*100)}%`,false],
                  ["양도소득세",fmtWon(result.yangdo),false],
                  ["지방소득세 (10%)",fmtWon(result.local),false],
                ].map(([k,v,h],i)=><ResultRow key={k} k={k} v={v} highlight={h}/>)}
                <div style={{paddingTop:10,marginTop:6,borderTop:"1px solid rgba(201,168,76,0.25)",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <span style={{color:C.gold,fontSize:13,fontWeight:600}}>총 예상 납부세액</span>
                  <span style={{color:C.goldLight,fontWeight:800,fontSize:20}}>{fmtWon(result.total)}</span>
                </div>
              </>
            )}
          </ResultBox>
          <CalcWarn/>
        </CalcCard>
      )}
    </>
  );
}

