            <svg width="16" height="16" viewBox="0 0 32 32" fill="none"><path d="M6 4h6l3 7-3.5 2.5c1.5 3 4 5.5 7 7L21 17l7 3v6a2 2 0 01-2 2C10 27 4 10 4 6a2 2 0 012-2z" fill={C.navy}/></svg>
